"""Конфигурация и состояние модуля yandex_ocr (секция [YANDEX_OCR] в app.ini, runtime)."""from __future__ import annotationsfrom dataclasses import dataclassfrom pathlib import Pathfrom typing import TYPE_CHECKINGif TYPE_CHECKING:    from .interfaces.response_logger import ResponseLoggerProtocol# Код провайдера (реестры, кеш, UI)PROVIDER_CODE = "yandex_ocr"# Модели Vision API: параметр model в запросе recognizeTextMODEL_TYPES = (    "page",    "page-column-sort",    "handwritten",    "table",    "markdown",    "math-markdown",)DEFAULT_MODEL = "page"@dataclass(frozen=True)class YandexOCRConfig:    """Настройки Yandex OCR из app.ini (включение и ключи API)."""    provider_enabled: bool = False    key_id: str = ""    key_secret: str = ""    def is_available(self) -> bool:        """True если провайдер включён и ключ задан."""        return bool(self.provider_enabled and (self.key_secret or "").strip())@dataclass(frozen=True)class ModuleConfig:    """Runtime-конфигурация модуля: api_config (YandexOCRConfig), путь к кешу (или None), опциональный логгер ответов API."""    api_config: YandexOCRConfig    cache_dir: Path | None    response_logger: ResponseLoggerProtocol | None = None    def is_available(self) -> bool:        """True если провайдер включён и ключ задан."""        return self.api_config.is_available()class ModuleConfigStore:    """Единая точка доступа к runtime-конфигурации модуля."""    _config: ModuleConfig | None = None    @classmethod    def set(cls, config: ModuleConfig) -> None:        cls._config = config    @classmethod    def get(cls) -> ModuleConfig:        if cls._config is None:            raise RuntimeError("yandex_ocr module is not initialized")        return cls._config    @classmethod    def reset(cls) -> None:        cls._config = Nonedef yandex_ocr_set_api_config(config: YandexOCRConfig) -> None:    """Обновить конфигурацию API в хранилище модуля (без перезапуска)."""    current = ModuleConfigStore.get()    ModuleConfigStore.set(        ModuleConfig(            api_config=config,            cache_dir=current.cache_dir,            response_logger=current.response_logger,        )    )